node - <<'NODE'
const fs=require('fs'), path=require('path');
const dir='.ypi/tasks/20260721-110132-修复-github-issues-9-10-11-上传路径穿越-oauth-超时与-mp4-尾部';
let bad=[];
for(const f of fs.readdirSync(dir).filter(x=>x.endsWith('.md')||x.endsWith('.json'))){
 const t=fs.readFileSync(path.join(dir,f),'utf8');
 t.split('\n').forEach((l,i)=>{if(/[ \t]+$/.test(l)) bad.push(`${f}:${i+1}`)});
 if(f.endsWith('.md')) for(const m of t.matchAll(/\]\(([^)]+)\)/g)){
   const target=m[1];
   if(!target.includes('://') && !target.startsWith('#') && !fs.existsSync(path.join(dir,target))) bad.push(`${f}: missing link ${target}`);
 }
}
if(bad.length){console.error(bad.join('\n'));process.exit(1)}
console.log('whitespace-and-local-links: ok');
NODE",
  "timeout": 20
}

